/**
 * n8n Code node (JavaScript)
 * Input sample:
 * items[0].json.output = "```json\n[ { \"Filename\":\"Intro.mp3\", \"VOText\":\"...\" }, ... ]\n```"
 * Output: multiple items, each { json: { Filename, VOText, index } }
 */

function stripFences(s) {
  const m = String(s).match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  return (m ? m[1] : String(s)).trim();
}

function stripLeadingJsonToken(s) {
  // Handles cases like "json[ ... ]"
  return s.replace(/^\s*json\s*(?=\[)/i, '').trim();
}

function parseArray(raw) {
  if (Array.isArray(raw)) return raw;
  if (raw && typeof raw === 'object') {
    // Try common wrappers if an object shows up
    const maybe = raw.data ?? raw.items ?? raw.result;
    if (Array.isArray(maybe)) return maybe;
  }
  let t = stripFences(String(raw));
  t = stripLeadingJsonToken(t).replace(/```/g, '').trim();
  return JSON.parse(t);
}

function validateRows(arr) {
  const out = [];
  for (const e of arr) {
    if (!e || typeof e !== 'object' || Array.isArray(e)) continue;
    const Filename = e.Filename;
    const VOText = e.VOText;
    if (typeof Filename !== 'string' || !/\.mp3$/i.test(Filename) || !Filename.trim()) continue;
    if (typeof VOText !== 'string' || !VOText.trim()) continue;
    out.push({ Filename: Filename.trim(), VOText: VOText.trim() });
  }
  if (!out.length) throw new Error('No valid VO entries after validation.');
  return out;
}

// ---- MAIN ----
if (!items?.[0]?.json) throw new Error('No input item found.');

const src = items[0].json;
// Prefer .output, fall back to .text/.result, or root
const raw = src.output ?? src.text ?? src.result ?? src;

const arr = validateRows(parseArray(raw));

// Return ONE ITEM PER VO (each item.json MUST be an OBJECT)
return arr.map((row, i) => ({ json: { ...row, index: i } }));

// ===================== GUARD =====================
if (!items || !items.length) {
  throw new Error("No input items found.");
}

// ===================== HELPERS =====================
const norm = (v) => (v === undefined || v === null ? "" : String(v).trim());

const sanitizeFilename = (name) => {
  let s = norm(name);
  s = s.replace(/[\\/:*?"<>|\u0000-\u001F]+/g, "_");
  s = s.replace(/\s+/g, " ").trim();
  s = s.replace(/[.\s]+$/g, "");
  return s || "audio";
};

const ensureMp3 = (name) =>
  name.toLowerCase().endsWith(".mp3") ? name : `${name}.mp3`;

const firstKey = (row, keys) => {
  for (const k of keys) {
    if (row && row[k] !== undefined && row[k] !== null) return row[k];
  }
  return undefined;
};

// ===================== COLLECT ROWS =====================
function collectRows(items) {
  const acc = [];
  for (const it of items) {
    const j = it?.json;
    if (!j) continue;

    if (Array.isArray(j)) acc.push(...j);
    else if (typeof j === "object") {
      const maybe = j.data ?? j.rows ?? j.items ?? j.output ?? j;
      if (Array.isArray(maybe)) acc.push(...maybe);
      else if (typeof maybe === "object") acc.push(maybe);
    }
  }
  return acc;
}

// ===================== READ WEBHOOK =====================
let webhookBody = {};
let voiceOverConfig = {};
let language = "English";
let voiceArtist = "";
let model = "";
let content = "";

try {
  const w = $items("Webhook1")?.[0]?.json?.body ?? {};
  webhookBody = w;
  voiceOverConfig = w.voiceOverConfig ?? {};
  language = norm($('Webhook1').first().json.body.language) || "English";
  voiceArtist = norm(w.voice_artist);
  model = w.model_id
  content = w.content
} catch (_) {
  webhookBody = {};
  voiceOverConfig = {};
  language = "English";
  voiceArtist = "";
  model = "";
}

// ===================== VOICE ARTIST → VOICE ID MAP =====================
const VOICE_MAP = {
  Raju: "21m00Tcm4TlvDq8ikWAM",
  Anika: "VOICE_ID_ANIKA",
  Maya: "VOICE_ID_MAYA"
};

const voiceId =
  VOICE_MAP[voiceArtist] ||
  voiceOverConfig.id ||
  "21m00Tcm4TlvDq8ikWAM";

// ===================== PREP ROWS =====================
const rows = collectRows(items);
if (!rows.length) {
  throw new Error("No rows detected.");
}

// ===================== MAIN =====================
const out = [];
const usedNames = new Map();


// 🔥🔥🔥 NEW — SCENE DEDUPE ONLY (ADDED FEATURE)
const seenScenes = new Set();
// 🔥🔥🔥


rows.forEach((row, i) => {

  // -------- Scene --------
  const scene = norm(firstKey(row, [
    "Scene Number", "SceneNumber", "sceneNumber",
    "Scene", "scene", "Shot", "Shot Number"
  ]));

  // 🔥🔥🔥 NEW — SKIP REPEATED SCENES
  if (seenScenes.has(scene)) return;
  seenScenes.add(scene);
  // 🔥🔥🔥

  // -------- VO Text --------
  let vo = norm(firstKey(row, [
    "Narration", "VO", "VoiceOver", "VO Text",
    "Script", "Text", "Description"
  ]));

  if (/^[-–—\s]+$/.test(vo)) vo = "";

  // -------- Filename --------
  const baseRaw = scene || `scene_${i + 1}`;
  let base = sanitizeFilename(baseRaw);

  const used = usedNames.get(base) || 0;
  usedNames.set(base, used + 1);
  if (used > 0) base = `${base}_${used + 1}`;

  const fileName = ensureMp3(base);

  // -------- OUTPUT --------
  out.push({
    json: {
      File_name: fileName,
      content: content,
      VOText: vo,
      language,
      index: i,

      model_id: model,
      id: voiceId,
      stability: Number(voiceOverConfig.stability ?? 0.5),
      similarity_boost: Number(voiceOverConfig.similarity_boost ?? 0.5),
      style: Number(voiceOverConfig.style ?? 0),
      speed: Number(voiceOverConfig.speed ?? 1),
      use_speaker_boost: Boolean(voiceOverConfig.use_speaker_boost ?? false)
    }
  });
});

return out;

/**
 * n8n Code node (JavaScript)
 * - Processes ALL incoming items
 * - Keeps voice_settings strictly for engine parameters
 * - Outputs VOText & File_name at top level
 * - Includes model_id explicitly
 * - Model-safe (only sends supported params)
 */

/* ================= Helpers ================= */

const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : undefined;
};

const toBool = (v) => {
  if (typeof v === 'boolean') return v;
  if (typeof v === 'number') return v !== 0;
  if (typeof v === 'string') {
    const s = v.toLowerCase();
    if (['true', '1', 'yes', 'y'].includes(s)) return true;
    if (['false', '0', 'no', 'n'].includes(s)) return false;
  }
  return undefined;
};

const clamp = (n, min, max) =>
  typeof n === 'number' ? Math.min(Math.max(n, min), max) : undefined;

const ensureMp3 = (name, fallback) => {
  let out = (name ?? fallback ?? '').toString().trim();
  if (!out) out = 'audio.mp3';

  if (!out.toLowerCase().endsWith('.mp3')) {
    const dot = out.lastIndexOf('.');
    if (dot > 0) out = out.slice(0, dot);
    out += '.mp3';
  }
  return out;
};

/* ================= Main ================= */

const items = $input.all();

const results = items.map((item, idx) => {
  const j = item.json ?? {};
  const cfg = j.body?.voiceOverConfig ?? {};

  /** Voice engine parameters ONLY */
  const voice_settings = {};

  if (cfg.id) voice_settings.id = cfg.id;
  if (cfg.stability !== undefined)
    voice_settings.stability = clamp(toNum(cfg.stability), 0, 1);
  if (cfg.similarity_boost !== undefined)
    voice_settings.similarity_boost = clamp(toNum(cfg.similarity_boost), 0, 1);
  if (cfg.style !== undefined)
    voice_settings.style = toNum(cfg.style);
  if (cfg.speed !== undefined)
    voice_settings.speed = clamp(toNum(cfg.speed), 0.25, 2);
  if (cfg.use_speaker_boost !== undefined)
    voice_settings.use_speaker_boost = toBool(cfg.use_speaker_boost);

  return {
    json: {
      model_id: j.body?.model_id,                 // ✅ model at top level
      VOText: (j.VOText ?? '').toString(),        // ✅ outside voice_settings
      File_name: ensureMp3(j.Filename, `audio_${idx + 1}.mp3`),
      voice_settings,                             // ✅ engine-only config
      item_index: idx,
    },
    ...(item.binary ? { binary: item.binary } : {}),
  };
});

return results;

